--
-- Table structure for table `wa_rules`
--

DROP TABLE IF EXISTS `wa_rules`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `wa_rules` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT COMMENT 'Khóa chính',
  `title` varchar(255) NOT NULL COMMENT 'Tiêu đề',
  `icon` varchar(255) DEFAULT NULL COMMENT 'Biểu tượng',
  `key` varchar(255) NOT NULL COMMENT 'Mã định danh',
  `pid` int(10) unsigned DEFAULT '0' COMMENT 'ID menu cấp trên',
  `created_at` datetime NOT NULL COMMENT 'Thời gian tạo',
  `updated_at` datetime NOT NULL COMMENT 'Thời gian cập nhật',
  `href` varchar(255) DEFAULT NULL COMMENT 'url',
  `type` int(11) NOT NULL DEFAULT '1' COMMENT 'Loại',
  `weight` int(11) DEFAULT '0' COMMENT 'Sắp xếp',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=1206 DEFAULT CHARSET=utf8mb4 COMMENT='Bảng quy tắc quyền hạn';
/*!40101 SET character_set_client = @saved_cs_client */;

